const body = $input.item.json.body || $input.item.json;

let channel = 'Unknown';
let senderId = '';
let messageText = '';
let senderName = '';

if ($node['Facebook Messenger Trigger'] && $node['Facebook Messenger Trigger'].json) {
  channel = 'Facebook';
  const entry = body.entry?.[0];
  const messaging = entry?.messaging?.[0];
  senderId = messaging?.sender?.id || '';
  messageText = messaging?.message?.text || '';
  senderName = messaging?.sender?.name || 'Customer';
} else if ($node['Instagram DM Trigger'] && $node['Instagram DM Trigger'].json) {
  channel = 'Instagram';
  const entry = body.entry?.[0];
  const messaging = entry?.messaging?.[0];
  senderId = messaging?.sender?.id || '';
  messageText = messaging?.message?.text || '';
  senderName = messaging?.sender?.name || 'Customer';
} else if ($node['WhatsApp Trigger'] && $node['WhatsApp Trigger'].json) {
  channel = 'WhatsApp';
  const message = body.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
  senderId = message?.from || '';
  messageText = message?.text?.body || '';
  senderName = body.entry?.[0]?.changes?.[0]?.value?.contacts?.[0]?.profile?.name || 'Customer';
}

return {
  json: {
    channel,
    senderId,
    messageText,
    senderName,
    timestamp: new Date().toISOString()
  }
};

const aiReply = $input.item.json.message?.content || '';

// Extract ORDER_DATA if present
let orderData = null;
let cleanReply = aiReply;

const orderMatch = aiReply.match(/<ORDER_DATA>([\s\S]*?)<\/ORDER_DATA>/);
if (orderMatch) {
  try {
    orderData = JSON.parse(orderMatch[1].trim());
    cleanReply = aiReply.replace(/<ORDER_DATA>[\s\S]*?<\/ORDER_DATA>/, '').trim();
  } catch (e) {
    orderData = null;
  }
}

// Generate order number if confirmed
let orderNumber = '';
if (orderData && orderData.order_confirmed) {
  const now = new Date();
  orderNumber = 'BAE-' + now.getFullYear() + 
    String(now.getMonth()+1).padStart(2,'0') + 
    String(now.getDate()).padStart(2,'0') + '-' + 
    Math.floor(Math.random() * 9000 + 1000);
  orderData.order_number = orderNumber;
  orderData.order_date = now.toISOString();
  cleanReply = cleanReply.replace('[AUTO GENERATED]', orderNumber);
}

return {
  json: {
    ...$input.item.json,
    aiReply: cleanReply,
    orderData: orderData,
    orderConfirmed: orderData ? orderData.order_confirmed : false,
    orderNumber
  }
};

// Update session history in Redis
const sessionKey = 'session_' + $input.item.json.senderId;
const existingSession = $input.item.json.sessionData 
  ? JSON.parse($input.item.json.sessionData) 
  : { history: [] };

existingSession.history.push(
  { role: 'user', content: $input.item.json.messageText },
  { role: 'assistant', content: $input.item.json.aiReply }
);

// Keep only last 20 messages to avoid token overflow
if (existingSession.history.length > 20) {
  existingSession.history = existingSession.history.slice(-20);
}

if ($input.item.json.orderConfirmed) {
  existingSession.orderConfirmed = true;
  existingSession.orderData = $input.item.json.orderData;
}

return {
  json: {
    ...$input.item.json,
    sessionKey,
    updatedSession: JSON.stringify(existingSession)
  }
};

